const item = $input.first().json;

// --- 1. ESTRAZIONE DATI ---
// Estraiamo l'ID del servizio dalla callback (es. m_mkt_do_broad_SVC_STBZ2RG7)
const callbackData = item.body?.callback_query?.data || "";
const svcId = callbackData.split('broad_')[1] || "SVC_STBZ2RG7";
const currentBalance = item.owner_data?.credits_balance || 0;

// --- 2. TESTO DEL MESSAGGIO (Versione Sospensione Tecnica) ---
const msgText = `
🚧 <b>MANUTENZIONE ARCHITETTURALE</b>
━━━━━━━━━━━━━━━━━━━━
Il modulo <b>Broadcast Community</b> è temporaneamente in modalità "Sola Lettura" per:
📦 <b>Protocollo Di Accoglienza Clienti</b>

📌 <b>Stato del Sistema:</b>
├ <b>Status:</b> 🟠 Sospeso (Deep Calibration)
├ <b>Motivo:</b> Verifica accoppiamento Owner/Stakeholder
├ <b>Crediti Scalati:</b> 0 cr. (Operazione Annullata)
└ <b>Saldo Invariato:</b> ${currentBalance} cr.

<i>Stiamo ottimizzando le logiche di distribuzione tra la proprietà e i portatori d'interesse. Il servizio tornerà operativo al termine della calibrazione.</i>
━━━━━━━━━━━━━━━━━━━━
`;

// --- 3. OUTPUT ---
return [{ json: { 
    ...item, 
    telegramApiPayload: {
        method: "editMessageText", 
        chat_id: item.owner_data.chat_id, 
        message_id: item.body.callback_query.message.message_id,
        text: msgText, 
        parse_mode: "HTML", 
        reply_markup: { 
            inline_keyboard: [
                [
                    { text: "🔙 Torna Indietro", callback_data: `m_mkt_id_${svcId}` }
                ]
            ] 
        }
    }
}}];
